      });

      it(`{pass: true} expect(${stringify(big)}).toBeGreaterThan(${stringify(
        small,
      )})`, () => {
        jestExpect(big).toBeGreaterThan(small);
      });

      it(`{pass: false} expect(${stringify(small)}).toBeGreaterThan(${stringify(
        big,
      )})`, () => {
